import React, { useState } from 'react';
import { writeProposal } from '../services/aiService';

// Page: Proposal Writer
// Collects inputs and asks OpenRouter to generate a full proposal.
const ProposalWriter = () => {
  const [form, setForm] = useState({ clientName: '', company: '', scope: '', budget: '', timeline: '', technologies: '', yourName: '' });
  const [result, setResult] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleGenerate = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    setResult('');
    
    const res = await writeProposal(
      form.clientName,
      form.company,
      form.scope,
      form.budget,
      form.timeline,
      form.technologies,
      form.yourName
    );
    
    if (res.success) {
      setResult(res.proposal);
    } else {
      setError(res.error);
    }
    setLoading(false);
  };

  const copyToClipboard = async () => {
    try {
      await navigator.clipboard.writeText(typeof result === 'string' ? result : JSON.stringify(result));
      alert('Copied to clipboard');
    } catch (err) {
      console.error(err);
      alert('Copy failed');
    }
  };

  return (
    <div>
      <h2>AI Proposal Writer</h2>
      <form onSubmit={handleGenerate}>
        <input name="clientName" placeholder="Client name" value={form.clientName} onChange={handleChange} required />
        <input name="company" placeholder="Company" value={form.company} onChange={handleChange} required />
        <textarea name="scope" placeholder="Project scope" value={form.scope} onChange={handleChange} required style={{ minHeight: 80 }} />
        <input name="budget" placeholder="Budget quote" value={form.budget} onChange={handleChange} required />
        <input name="timeline" placeholder="Timeline" value={form.timeline} onChange={handleChange} required />
        <input name="technologies" placeholder="Technologies (optional)" value={form.technologies} onChange={handleChange} />
        <input name="yourName" placeholder="Your name / brand" value={form.yourName} onChange={handleChange} />
        <button type="submit" disabled={loading}>{loading ? 'Writing...' : 'Write Proposal'}</button>
      </form>

      {error && <p style={{ color: 'red', marginTop: 20 }}>{error}</p>}
      
      {result && (
        <div style={{ marginTop: 20 }}>
          <button onClick={copyToClipboard}>Copy to clipboard</button>
          <pre style={{ whiteSpace: 'pre-wrap', border: '1px solid #ddd', padding: 10 }}>{result}</pre>
        </div>
      )}
    </div>
  );
};

export default ProposalWriter;
